from decimal import Decimal
from django.contrib.auth.models import User


class CartService:
    """Servicio para gestionar la cesta de compra en sesión."""

    CART_SESSION_KEY = 'cart'

    @staticmethod
    def get_cart(request):
        """Obtiene la cesta de la sesión."""
        if CartService.CART_SESSION_KEY not in request.session:
            request.session[CartService.CART_SESSION_KEY] = {}
        return request.session[CartService.CART_SESSION_KEY]

    @staticmethod
    def add_to_cart(request, barco_id, cantidad):
        """Añade un barco a la cesta."""
        cart = CartService.get_cart(request)
        barco_id_str = str(barco_id)

        if barco_id_str in cart:
            cart[barco_id_str]['cantidad'] += int(cantidad)
        else:
            from catalog.models import Barco
            barco = Barco.objects.get(id=barco_id)
            cart[barco_id_str] = {
                'barco_id': barco_id,
                'nombre': barco.nombre,
                'precio_dia': str(barco.precio_dia),
                'cantidad': int(cantidad),
            }

        request.session[CartService.CART_SESSION_KEY] = cart
        request.session.modified = True

    @staticmethod
    def update_cart(request, barco_id, cantidad):
        """Actualiza la cantidad de un barco en la cesta."""
        cart = CartService.get_cart(request)
        barco_id_str = str(barco_id)

        if barco_id_str in cart:
            cantidad = int(cantidad)
            if cantidad > 0:
                cart[barco_id_str]['cantidad'] = cantidad
            else:
                del cart[barco_id_str]

        request.session[CartService.CART_SESSION_KEY] = cart
        request.session.modified = True

    @staticmethod
    def remove_from_cart(request, barco_id):
        """Elimina un barco de la cesta."""
        cart = CartService.get_cart(request)
        barco_id_str = str(barco_id)

        if barco_id_str in cart:
            del cart[barco_id_str]

        request.session[CartService.CART_SESSION_KEY] = cart
        request.session.modified = True

    @staticmethod
    def clear_cart(request):
        """Vacía la cesta completamente."""
        request.session[CartService.CART_SESSION_KEY] = {}
        request.session.modified = True

    @staticmethod
    def get_cart_items(request):
        """Obtiene los items de la cesta con información completa."""
        from catalog.models import Barco

        cart = CartService.get_cart(request)
        items = []

        for barco_id_str, item in cart.items():
            try:
                barco = Barco.objects.get(id=int(barco_id_str))
                items.append({
                    'barco': barco,
                    'cantidad': item['cantidad'],
                    'precio_unitario': Decimal(item['precio_dia']),
                    'subtotal': Decimal(item['precio_dia']) * item['cantidad'],
                })
            except Barco.DoesNotExist:
                pass

        return items

    @staticmethod
    def get_cart_total(request):
        """Calcula el total de la cesta."""
        items = CartService.get_cart_items(request)
        total = sum(item['subtotal'] for item in items)
        return total

    @staticmethod
    def get_cart_count(request):
        """Obtiene el número total de items en la cesta."""
        cart = CartService.get_cart(request)
        return sum(item['cantidad'] for item in cart.values())

    @staticmethod
    def is_cart_empty(request):
        """Verifica si la cesta está vacía."""
        cart = CartService.get_cart(request)
        return len(cart) == 0

