class PricingService:
    """Servicio para calcular precios de reservas."""

    TASA_COMBUSTIBLE_DIARIA = Decimal('50.00')
    CATEGORIA_EXENTA_COMBUSTIBLE = 'Velero'

    @staticmethod
    def calcular_dias(fecha_inicio, fecha_fin):
        """Calcula el número de días entre dos fechas."""
        delta = fecha_fin - fecha_inicio
        return max(1, delta.days)

    @staticmethod
    def calcular_tasa_combustible(barco, dias):
        """Calcula la tasa de combustible según la categoría del barco."""
        if barco.categoria.nombre == PricingService.CATEGORIA_EXENTA_COMBUSTIBLE:
            return Decimal('0.00')
        return PricingService.TASA_COMBUSTIBLE_DIARIA * dias

    @staticmethod
    def calcular_precio_total(barco, cantidad, fecha_inicio, fecha_fin):
        """Calcula el precio total de una reserva."""
        dias = PricingService.calcular_dias(fecha_inicio, fecha_fin)
        precio_barco = barco.precio_dia * cantidad * dias
        tasa_combustible = PricingService.calcular_tasa_combustible(barco, dias)
        total = precio_barco + tasa_combustible
        return {
            'dias': dias,
            'precio_barco': precio_barco,
            'tasa_combustible': tasa_combustible,
            'total': total,
        }

