class CheckoutStep1Form(forms.Form):
    """Formulario para el paso 1 del checkout: datos del cliente."""

    nombre_cliente = forms.CharField(
        max_length=120,
        required=True,
        widget=forms.TextInput(attrs={
            'class': 'form-control',
            'placeholder': 'Nombre completo',
        })
    )

    email_cliente = forms.EmailField(
        required=True,
        widget=forms.EmailInput(attrs={
            'class': 'form-control',
            'placeholder': 'Correo electrónico',
        })
    )

    telefono_cliente = forms.CharField(
        max_length=20,
        required=False,
        widget=forms.TextInput(attrs={
            'class': 'form-control',
            'placeholder': 'Teléfono (opcional)',
        })
    )

    fecha_inicio = forms.DateField(
        required=True,
        widget=forms.DateInput(attrs={
            'class': 'form-control',
            'type': 'date',
        })
    )

    fecha_fin = forms.DateField(
        required=True,
        widget=forms.DateInput(attrs={
            'class': 'form-control',
            'type': 'date',
        })
    )

    def clean_nombre_cliente(self):
        nombre = self.cleaned_data.get('nombre_cliente')
        if nombre and len(nombre.strip()) < 3:
            raise ValidationError('El nombre debe tener al menos 3 caracteres.')
        return nombre

    def clean_telefono_cliente(self):
        telefono = self.cleaned_data.get('telefono_cliente')
        if telefono and len(telefono.strip()) > 0:
            # Validación simple de teléfono
            if not telefono.replace('+', '').replace('-', '').replace(' ', '').isdigit():
                raise ValidationError('El teléfono debe contener solo números, espacios, + o -.')
        return telefono

    def clean_fecha_inicio(self):
        fecha_inicio = self.cleaned_data.get('fecha_inicio')
        if fecha_inicio and fecha_inicio < date.today():
            raise ValidationError('La fecha de inicio no puede ser anterior a hoy.')
        return fecha_inicio

    def clean(self):
        cleaned_data = super().clean()
        fecha_inicio = cleaned_data.get('fecha_inicio')
        fecha_fin = cleaned_data.get('fecha_fin')

        if fecha_inicio and fecha_fin:
            if fecha_fin <= fecha_inicio:
                raise ValidationError('La fecha de fin debe ser posterior a la fecha de inicio.')

        return cleaned_data


