class CheckoutStep3View(TemplateView):
    template_name = 'reservations/checkout_step3.html'

    def get_context_data(self, **kwargs):
        context = super().get_context_data(**kwargs)
        context['form'] = CheckoutStep3Form()
        context['cart_items'] = CartService.get_cart_items(self.request)
        context['cart_total'] = CartService.get_cart_total(self.request)

        # Verificar que los pasos anteriores fueron completados
        if 'checkout_step1' not in self.request.session or 'checkout_step2' not in self.request.session:
            context['error'] = 'Debes completar los pasos anteriores primero.'
        else:
            # Calcular desglose de precios
            step1 = self.request.session['checkout_step1']
            from datetime import datetime
            fecha_inicio = datetime.fromisoformat(step1['fecha_inicio']).date()
            fecha_fin = datetime.fromisoformat(step1['fecha_fin']).date()

            items = CartService.get_cart_items(self.request)
            desglose = []
            total_general = 0

            for item in items:
                pricing = PricingService.calcular_precio_total(
                    item['barco'],
                    item['cantidad'],
                    fecha_inicio,
                    fecha_fin
                )
                desglose.append({
                    'barco': item['barco'],
                    'cantidad': item['cantidad'],
                    'dias': pricing['dias'],
                    'precio_barco': pricing['precio_barco'],
                    'tasa_combustible': pricing['tasa_combustible'],
                    'total': pricing['total'],
                })
                total_general += pricing['total']

            context['desglose'] = desglose
            context['total_general'] = total_general

        return context

    def post(self, request, *args, **kwargs):
        if 'checkout_step1' not in request.session or 'checkout_step2' not in request.session:
            messages.error(request, 'Debes completar los pasos anteriores primero.')
            return redirect('reservations:checkout_step1')

        form = CheckoutStep3Form(request.POST)

        if form.is_valid():
            try:
                with transaction.atomic():
                    step1 = request.session['checkout_step1']
                    step2 = request.session['checkout_step2']

                    from datetime import datetime
                    fecha_inicio = datetime.fromisoformat(step1['fecha_inicio']).date()
                    fecha_fin = datetime.fromisoformat(step1['fecha_fin']).date()

                    items = CartService.get_cart_items(request)

                    # Crear una reserva por cada item en la cesta
                    for item in items:
                        pricing = PricingService.calcular_precio_total(
                            item['barco'],
                            item['cantidad'],
                            fecha_inicio,
                            fecha_fin
                        )

                        reserva = Reserva.objects.create(
                            codigo_seguimiento=str(uuid.uuid4())[:32],
                            cliente=request.user if request.user.is_authenticated else None,
                            nombre_cliente=step1['nombre_cliente'],
                            email_cliente=step1['email_cliente'],
                            telefono_cliente=step1['telefono_cliente'],
                            barco=item['barco'],
                            cantidad=item['cantidad'],
                            fecha_inicio=fecha_inicio,
                            fecha_fin=fecha_fin,
                            precio_unitario_dia=item['barco'].precio_dia,
                            tasa_combustible_dia=PricingService.TASA_COMBUSTIBLE_DIARIA if item['barco'].categoria.nombre != 'Velero' else 0,
                            importe_total=pricing['total'],
                            metodo_pago=step2['metodo_pago'],
                        )

                        # Registrar cambio de estado
                        HistorialEstadoReserva.objects.create(
                            reserva=reserva,
                            estado_anterior='',
                            estado_nuevo='PENDIENTE_DE_PAGO',
                            cambio_por=request.user if request.user.is_authenticated else None,
                            notas='Reserva creada',
                        )

                        # Enviar correo de confirmación
                        EmailService.enviar_confirmacion_reserva(reserva)

                    # Limpiar sesión y cesta
                    CartService.clear_cart(request)
                    del request.session['checkout_step1']
                    del request.session['checkout_step2']
                    request.session.modified = True

                    messages.success(request, 'Reserva completada exitosamente.')
                    return redirect('reservations:confirmation')

            except Exception as e:
                messages.error(request, f'Error al crear la reserva: {str(e)}')
                return redirect('reservations:checkout_step3')

        context = self.get_context_data(**kwargs)
        context['form'] = form
        return render(request, self.template_name, context)


