class CancelReservationView(View):
    @method_decorator(require_http_methods(['POST']))
    @method_decorator(login_required(login_url='accounts:login'))
    def post(self, request, id):
        reserva = get_object_or_404(Reserva, id=id, cliente=request.user)

        if reserva.estado == 'CANCELADO':
            messages.warning(request, 'Esta reserva ya ha sido cancelada.')
        elif reserva.estado == 'EN_USO' or reserva.estado == 'DEVUELTO':
            messages.error(request, 'No se puede cancelar una reserva en uso o devuelta.')
        else:
            estado_anterior = reserva.estado
            reserva.estado = 'CANCELADO'
            reserva.save()

            HistorialEstadoReserva.objects.create(
                reserva=reserva,
                estado_anterior=estado_anterior,
                estado_nuevo='CANCELADO',
                cambio_por=request.user,
                notas='Cancelada por el cliente',
            )

            messages.success(request, 'Reserva cancelada exitosamente.')

        return redirect('accounts:my_reservations')

from django.shortcuts import render, redirect
