{% extends 'base.html' %}

{% block title %}Reserva - Paso 1 - Hundidos{% endblock %}

{% block content %}
<div class="container my-5">
    <div class="row">
        <div class="col-md-8">
            <h2>Reserva - Paso 1: Datos del Cliente</h2>

            {% if cart_items %}
                <div class="card mb-4">
                    <div class="card-body">
                        <h5 class="card-title">Resumen de la Cesta</h5>
                        <table class="table table-sm">
                            <thead>
                                <tr>
                                    <th>Barco</th>
                                    <th>Cantidad</th>
                                    <th>Precio/Día</th>
                                </tr>
                            </thead>
                            <tbody>
                                {% for item in cart_items %}
                                    <tr>
                                        <td>{{ item.barco.nombre }}</td>
                                        <td>{{ item.cantidad }}</td>
                                        <td>{{ item.precio_unitario }}€</td>
                                    </tr>
                                {% endfor %}
                            </tbody>
                        </table>
                    </div>
                </div>

                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Información del Cliente</h5>
                        <form method="post" novalidate>
                            {% csrf_token %}

                            <div class="mb-3">
                                <label for="{{ form.nombre_cliente.id_for_label }}" class="form-label">Nombre Completo *</label>
                                {{ form.nombre_cliente }}
                                {% if form.nombre_cliente.errors %}
                                    <div class="invalid-feedback d-block">
                                        {% for error in form.nombre_cliente.errors %}
                                            {{ error }}
                                        {% endfor %}
                                    </div>
                                {% endif %}
                            </div>

                            <div class="mb-3">
                                <label for="{{ form.email_cliente.id_for_label }}" class="form-label">Correo Electrónico *</label>
                                {{ form.email_cliente }}
                                {% if form.email_cliente.errors %}
                                    <div class="invalid-feedback d-block">
                                        {% for error in form.email_cliente.errors %}
                                            {{ error }}
                                        {% endfor %}
                                    </div>
                                {% endif %}
                            </div>

                            <div class="mb-3">
                                <label for="{{ form.telefono_cliente.id_for_label }}" class="form-label">Teléfono</label>
                                {{ form.telefono_cliente }}
                                {% if form.telefono_cliente.errors %}
                                    <div class="invalid-feedback d-block">
                                        {% for error in form.telefono_cliente.errors %}
                                            {{ error }}
                                        {% endfor %}
                                    </div>
                                {% endif %}
                            </div>

                            <hr>

                            <h5 class="card-title">Fechas de la Reserva</h5>

                            <div class="row">
                                <div class="col-md-6 mb-3">
                                    <label for="{{ form.fecha_inicio.id_for_label }}" class="form-label">Fecha de Inicio *</label>
                                    {{ form.fecha_inicio }}
                                    {% if form.fecha_inicio.errors %}
                                        <div class="invalid-feedback d-block">
                                            {% for error in form.fecha_inicio.errors %}
                                                {{ error }}
                                            {% endfor %}
                                        </div>
                                    {% endif %}
                                </div>

                                <div class="col-md-6 mb-3">
                                    <label for="{{ form.fecha_fin.id_for_label }}" class="form-label">Fecha de Fin *</label>
                                    {{ form.fecha_fin }}
                                    {% if form.fecha_fin.errors %}
                                        <div class="invalid-feedback d-block">
                                            {% for error in form.fecha_fin.errors %}
                                                {{ error }}
                                            {% endfor %}
                                        </div>
                                    {% endif %}
                                </div>
                            </div>

                            {% if form.non_field_errors %}
                                <div class="alert alert-danger">
                                    {% for error in form.non_field_errors %}
                                        {{ error }}
                                    {% endfor %}
                                </div>
                            {% endif %}

                            <div class="d-flex gap-2">
                                <a href="{% url 'cart:summary' %}" class="btn btn-secondary">Volver a la Cesta</a>
                                <button type="submit" class="btn btn-primary">Continuar al Paso 2</button>
                            </div>
                        </form>
                    </div>
                </div>
            {% else %}
                <div class="alert alert-warning">
                    Tu cesta está vacía. <a href="{% url 'catalog:barco_list' %}">Añade barcos antes de continuar.</a>
                </div>
            {% endif %}
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Pasos de la Reserva</h5>
                    <div class="list-group">
                        <div class="list-group-item active">Paso 1: Datos del Cliente</div>
                        <div class="list-group-item">Paso 2: Método de Pago</div>
                        <div class="list-group-item">Paso 3: Confirmación</div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>
{% endblock %}
